import{_ as e}from"./chunks/20260701102310.BjVabdSf.js";import{_ as r,c as t,o as i,aN as l}from"./chunks/framework.CRrpcmb4.js";const _=JSON.parse('{"title":"关于","description":"","frontmatter":{"date":"2025-12-08T11:55:14.000Z","title":"关于","permalink":"/pages/about","categories":["关于"]},"headers":[],"relativePath":"01.接口/01.关于.md","filePath":"01.接口/01.关于.md"}'),o={name:"01.接口/01.关于.md"};function n(s,a,h,d,g,c){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="xfx-plugin-安卓工具类插件" tabindex="-1">XFX Plugin - 安卓工具类插件 <a class="header-anchor" href="#xfx-plugin-安卓工具类插件" aria-label="Permalink to &quot;XFX Plugin - 安卓工具类插件&quot;">​</a></h1><h2 id="📖-简介" tabindex="-1">📖 简介 <a class="header-anchor" href="#📖-简介" aria-label="Permalink to &quot;📖 简介&quot;">​</a></h2><p>XFX Plugin（小飞侠插件） 是一个<strong>免费</strong>的专为安卓脚本开发框架设计的功能丰富的工具类插件，提供了超过 400+ 的 API 接口，方便安卓脚本开发者使用。</p><h3 id="主要特性" tabindex="-1">主要特性 <a class="header-anchor" href="#主要特性" aria-label="Permalink to &quot;主要特性&quot;">​</a></h3><ul><li>🚀 <strong>丰富的工具类</strong>：提供了大量常用工具类</li><li>📡 <strong>实时通信</strong>：集成 MQTT 客户端，支持实时消息通信</li><li>❤️ <strong>悬浮窗日志</strong>：由<code>雪落</code>大神提供的源码改进而来，支持在屏幕上实时输出运行日志</li><li>🗣️ <strong>文本转语音</strong>：支持 TTS 文本转语音功能</li><li>🎬 <strong>视频处理</strong>：集成 FFMPEG，支持视频处理、转换等操作</li><li>📱 <strong>设备操作</strong>：提供设备信息获取、屏幕操作、音量控制等功能</li><li>🔐 <strong>加密解密</strong>：支持多种加密算法，保障数据安全</li><li>🖼️ <strong>图像处理</strong>：支持图片压缩、二维码生成与识别等功能</li></ul><h2 id="信息处理" tabindex="-1">信息处理 <a class="header-anchor" href="#信息处理" aria-label="Permalink to &quot;信息处理&quot;">​</a></h2><p>XFX Plugin 不收集、获取或上传任何个人信息。</p><h2 id="📝-鸣谢" tabindex="-1">📝 鸣谢 <a class="header-anchor" href="#📝-鸣谢" aria-label="Permalink to &quot;📝 鸣谢&quot;">​</a></h2><p>本插件调用或借鉴了以下项目，特此感谢：</p><ul><li><a href="https://github.com/Blankj/AndroidUtilCode" target="_blank" rel="noreferrer">AndroidUtilCode</a> - 安卓工具库</li><li><a href="https://github.com/arthenica/ffmpeg-kit" target="_blank" rel="noreferrer">FFmpegKit</a> - FFmpeg Android封装</li><li><a href="https://github.com/eclipse/paho.mqtt.android" target="_blank" rel="noreferrer">Eclipse Paho MQTT</a> - MQTT客户端</li><li><a href="https://github.com/zxing/zxing" target="_blank" rel="noreferrer">ZXing</a> - 二维码处理库</li><li><a href="http://github.com/Tencent/ncnn/" target="_blank" rel="noreferrer">NCNN</a> - 神经网络推理库</li></ul><h2 id="💡-反馈交流" tabindex="-1">💡 反馈交流 <a class="header-anchor" href="#💡-反馈交流" aria-label="Permalink to &quot;💡 反馈交流&quot;">​</a></h2><p>在使用过程中有任何问题和想法，请与我取得联系。</p><h2 id="📞-联系方式" tabindex="-1">📞 联系方式 <a class="header-anchor" href="#📞-联系方式" aria-label="Permalink to &quot;📞 联系方式&quot;">​</a></h2><p><img src="'+e+'" alt="" loading="lazy"></p>',14)])])}const f=r(o,[["render",n]]);export{_ as __pageData,f as default};
